import React, { useEffect, useState } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import { authorize, refresh } from 'react-native-app-auth';

const config = {
  issuer: 'https://your-oauth-server.com',
  clientId: 'your_client_id',
  clientSecret: 'your_client_secret',
  redirectUrl: 'com.yourapp:/oauth2redirect',
  scopes: ['openid', 'profile', 'email'],
  serviceConfiguration: {
    authorizationEndpoint: 'https://your-oauth-server.com/auth',
    tokenEndpoint: 'https://your-oauth-server.com/token',
  },
};

const App = () => {
  const [authState, setAuthState] = useState(null);

  const signIn = async () => {
    try {
      const result = await authorize(config);
      setAuthState(result);
    } catch (error) {
      Alert.alert('Authentication Error', error.message);
    }
  };

  const refreshToken = async () => {
    if (authState) {
      try {
        const newAuthState = await refresh(config, {
          refreshToken: authState.refreshToken,
        });
        setAuthState(newAuthState);
      } catch (error) {
        Alert.alert('Token Refresh Error', error.message);
      }
    }
  };

  useEffect(() => {
    const interval = setInterval(() => {
      refreshToken();
    }, 600000); // Refresh token every 10 minutes

    return () => clearInterval(interval);
  }, [authState]);

  return (
    <View>
      <Text>OAuth 2.0 Authentication</Text>
      {authState ? (
        <Text>Welcome, {authState.accessToken}</Text>
      ) : (
        <Button title="Sign In" onPress={signIn} />
      )}
    </View>
  );
};

export default App;